UPDATE readiness_v1.assessment_schemas 
SET schema_json = schema_json::jsonb || jsonb_build_object('profile_questions', '[{"id": "profile.financial.has_beneficiary_accounts", "field": "financial.has_beneficiary_accounts", "prompt": "Do any of your accounts allow you to name beneficiaries?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.household.has_dependents", "field": "household.has_dependents", "prompt": "Do other people depend on you for care or financial support?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.pets.has_pets", "field": "pets.has_pets", "prompt": "Do you have pets that depend on you?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.digital.owns_crypto", "field": "digital.owns_crypto", "prompt": "Do you own any digital or cryptocurrency assets?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.family.supports_aging_parent", "field": "family.supports_aging_parent", "prompt": "Are you currently helping support an aging parent?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.home.owns_real_property", "field": "home.owns_real_property", "prompt": "Do you own your home or other real property?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.home.has_significant_personal_property", "field": "home.has_significant_personal_property", "prompt": "Do you own items of significant personal value?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}, {"id": "profile.emotional.has_spiritual_practices", "field": "emotional.has_spiritual_practices", "prompt": "Do you have spiritual or cultural practices you would want included?", "type": "single_select", "options": [{"value": "yes", "label": "Yes"}, {"value": "no", "label": "No"}], "value_map": {"yes": true, "no": false}}]'::jsonb)
WHERE assessment_id = 'readiness_v1' AND version = 'v1';